import React, { useState, useEffect, useRef } from 'react';
import { Play, Pause, RefreshCw, Settings, Clock, Coffee, Zap } from 'lucide-react';

export default function App() {
  const [workTime, setWorkTime] = useState(25);
  const [breakTime, setBreakTime] = useState(5);
  const [timeLeft, setTimeLeft] = useState(workTime * 60);
  const [isActive, setIsActive] = useState(false);
  const [isWork, setIsWork] = useState(true);

  useEffect(() => {
    let interval = null;
    if (isActive && timeLeft > 0) {
      interval = setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      setIsActive(false);
      setIsWork(!isWork);
      setTimeLeft((isWork ? breakTime : workTime) * 60);
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft, isWork, workTime, breakTime]);

  const toggleTimer = () => setIsActive(!isActive);
  const resetTimer = () => {
    setIsActive(false);
    setIsWork(true);
    setTimeLeft(workTime * 60);
  };

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="min-h-screen bg-slate-950 text-white flex flex-col items-center justify-center p-6 font-sans">
      <div className="w-full max-w-md bg-slate-900/50 p-8 rounded-3xl border border-slate-800 backdrop-blur-xl shadow-2xl">
        <div className="flex justify-between items-center mb-8">
          <h1 className="text-2xl font-bold tracking-tight">FocusFlow</h1>
          <div className={`px-3 py-1 rounded-full text-xs font-semibold flex items-center gap-2 ${isWork ? 'bg-indigo-500/20 text-indigo-400' : 'bg-emerald-500/20 text-emerald-400'}`}>
            {isWork ? <Zap size={14} /> : <Coffee size={14} />}
            {isWork ? 'FOCUS' : 'BREAK'}
          </div>
        </div>

        <div className="text-center py-8">
          <div className="text-8xl font-mono font-light tracking-tighter mb-8">
            {formatTime(timeLeft)}
          </div>

          <div className="flex justify-center gap-4">
            <button 
              onClick={toggleTimer}
              className="p-4 rounded-full bg-white text-slate-950 hover:scale-105 transition-all active:scale-95"
            >
              {isActive ? <Pause size={28} /> : <Play size={28} />}
            </button>
            <button 
              onClick={resetTimer}
              className="p-4 rounded-full bg-slate-800 text-slate-300 hover:bg-slate-700 transition-all"
            >
              <RefreshCw size={28} />
            </button>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4 mt-8 pt-8 border-t border-slate-800">
          <div>
            <label className="block text-xs text-slate-400 mb-2 uppercase tracking-wider">Work (min)</label>
            <input 
              type="number" 
              value={workTime}
              onChange={(e) => {
                const val = parseInt(e.target.value) || 1;
                setWorkTime(val);
                if (isWork) setTimeLeft(val * 60);
              }}
              className="w-full bg-slate-800 p-3 rounded-xl border border-slate-700 outline-none focus:border-indigo-500 transition-colors"
            />
          </div>
          <div>
            <label className="block text-xs text-slate-400 mb-2 uppercase tracking-wider">Break (min)</label>
            <input 
              type="number" 
              value={breakTime}
              onChange={(e) => setBreakTime(parseInt(e.target.value) || 1)}
              className="w-full bg-slate-800 p-3 rounded-xl border border-slate-700 outline-none focus:border-indigo-500 transition-colors"
            />
          </div>
        </div>
      </div>
    </div>
  );
}
